//nolint:testpackage
package metaaggregation

import (
	"math/big"
	"testing"

	"github.com/KyberNetwork/aggregator-encoding/pkg/encode/v3/router"
	"github.com/ethereum/go-ethereum/common"
	"github.com/ethereum/go-ethereum/common/hexutil"
	"github.com/stretchr/testify/assert"
)

func TestEncodeMetaAggregationRouterSwap(t *testing.T) {
	testCases := []struct {
		name     string
		input    router.SwapInputs
		expected []byte
	}{
		{
			name: "normal case",
			input: router.SwapInputs{
				Execution: router.SwapExecutionParams{
					CallTarget:    common.HexToAddress("0x1"),
					ApproveTarget: common.HexToAddress("0x2"),
					TargetData:    []byte("0x3"),
					Desc: router.SwapDescriptionV2{
						SrcToken:        common.HexToAddress("0x4"),
						DstToken:        common.HexToAddress("0x5"),
						SrcReceivers:    []common.Address{common.HexToAddress("0x6")},
						SrcAmounts:      []*big.Int{big.NewInt(1)},
						FeeReceivers:    []common.Address{common.HexToAddress("0x7")},
						FeeAmounts:      []*big.Int{big.NewInt(2)},
						DstReceiver:     common.HexToAddress("0x8"),
						Amount:          big.NewInt(3),
						MinReturnAmount: big.NewInt(4),
						Flags:           big.NewInt(5),
						Permit:          []byte("0x9"),
					},
					ClientData: []byte("0xa"),
				},
			},
			expected: hexutil.MustDecode(""),
		},
	}
	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			input := metaAggregationSwapInputs{}
			input.SwapInputs = tc.input
			result, err := EncodeMetaAggregationRouterSwapData(&input)
			assert.NoError(t, err)
			assert.Equal(t, tc.expected, result)
		})
	}
}

func TestDecodeMetaAggregationRouterSwap(t *testing.T) {
	testCases := []struct {
		name     string
		input    []byte
		expected router.SwapInputs
	}{
		{
			name:  "normal case",
			input: hexutil.MustDecode(""),
			expected: router.SwapInputs{
				Execution: router.SwapExecutionParams{
					CallTarget:    common.HexToAddress("0x1"),
					ApproveTarget: common.HexToAddress("0x2"),
					TargetData:    []byte("0x3"),
					Desc: router.SwapDescriptionV2{
						SrcToken:        common.HexToAddress("0x4"),
						DstToken:        common.HexToAddress("0x5"),
						SrcReceivers:    []common.Address{common.HexToAddress("0x6")},
						SrcAmounts:      []*big.Int{big.NewInt(1)},
						FeeReceivers:    []common.Address{common.HexToAddress("0x7")},
						FeeAmounts:      []*big.Int{big.NewInt(2)},
						DstReceiver:     common.HexToAddress("0x8"),
						Amount:          big.NewInt(3),
						MinReturnAmount: big.NewInt(4),
						Flags:           big.NewInt(5),
						Permit:          []byte("0x9"),
					},
					ClientData: []byte("0xa"),
				},
			},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			result, err := DecodeMetaAggregationRouterSwapData(tc.input)
			assert.NoError(t, err)
			// nolint: forcetypeassert
			assert.Equal(t, tc.expected, result.(*metaAggregationSwapInputs).SwapInputs)
		})
	}
}
